func skillFormAlpineData(sk *skill.Skill) string {
	if sk == nil {
		return `{
			formData: {
				name: '', description: '', default_proficiency: 'competent',
				system_prompt_fragment: '', tools: [], knowledge: []
			},
			dependenciesText: '',
			error: '',
			submitting: false,
			async submitForm() {
				this.submitting = true;
				this.error = '';
				const data = {...this.formData};
				data.dependencies = this.dependenciesText ? this.dependenciesText.split(',').map(s => s.trim()).filter(Boolean) : [];
				data.tools = data.tools.filter(t => t.tool_name.trim() !== '');
				data.knowledge = data.knowledge.filter(k => k.source.trim() !== '');
				try {
					const resp = await fetch('/cortex/skills', {method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(data)});
					if (resp.ok) { htmx.ajax('GET', '/ext/cortex/pages/skills', {target: '#content'}); }
					else { const r = await resp.json().catch(() => ({})); this.error = r.error || r.message || 'Failed to create skill'; }
				} catch(e) { this.error = e.message; }
				this.submitting = false;
			}
		}`
	}

	toolsJSON := buildToolBindingsJSON(sk.Tools)
	knowledgeJSON := buildKnowledgeRefsJSON(sk.Knowledge)

	return fmt.Sprintf(`{
		formData: {
			name: %q, description: %q, default_proficiency: %q,
			system_prompt_fragment: %q, tools: %s, knowledge: %s
		},
		dependenciesText: %q,
		error: '',
		submitting: false,
		async submitForm() {
			this.submitting = true;
			this.error = '';
			const data = {...this.formData};
			data.dependencies = this.dependenciesText ? this.dependenciesText.split(',').map(s => s.trim()).filter(Boolean) : [];
			data.tools = data.tools.filter(t => t.tool_name.trim() !== '');
			data.knowledge = data.knowledge.filter(k => k.source.trim() !== '');
			try {
				const resp = await fetch('/cortex/skills/%s', {method: 'PUT', headers: {'Content-Type': 'application/json'}, body: JSON.stringify(data)});
				if (resp.ok) { htmx.ajax('GET', '/ext/cortex/pages/skills/detail?name=%s', {target: '#content'}); }
				else { const r = await resp.json().catch(() => ({})); this.error = r.error || r.message || 'Failed to update skill'; }
			} catch(e) { this.error = e.message; }
			this.submitting = false;
		}
	}`,
		sk.Name, sk.Description, string(sk.DefaultProficiency),
		sk.SystemPromptFragment, toolsJSON, knowledgeJSON,
		strings.Join(sk.Dependencies, ", "),
		sk.Name, sk.Name,
	)
}

func buildToolBindingsJSON(tools []skill.ToolBinding) string {
	if len(tools) == 0 {
		return "[]"
	}
	items := make([]string, 0, len(tools))
	for _, t := range tools {
		items = append(items, fmt.Sprintf(`{"tool_name":%q,"mastery":%q,"guidance":%q,"prefer_when":%q}`,
			t.ToolName, string(t.Mastery), t.Guidance, t.PreferWhen))
	}
	return "[" + strings.Join(items, ",") + "]"
}

func buildKnowledgeRefsJSON(refs []skill.KnowledgeRef) string {
	if len(refs) == 0 {
		return "[]"
	}
	items := make([]string, 0, len(refs))
	for _, r := range refs {
		b, _ := json.Marshal(r)
		items = append(items, string(b))
	}
	return "[" + strings.Join(items, ",") + "]"
}

